  (64, 'Nghịch Phong Đoạt', 'Sử dụng Thâu Thủ đối với kẻ địch để lấy tất cả những trạng thái có lợi sang mình, duy trì liên tục 3 hiệp.', 6, 1, 10, 0, 11, 1, 0),
